SELECT COUNT(*) FROM customers WHERE is_deleted = 0
AND created_at BETWEEN #{start} AND #{end}
AND (inviter_user_id = #{userId} OR owner_user_id = #{userId})

SELECT COUNT(*) FROM task_boards WHERE is_deleted = 0
AND status = '已完成' AND updated_at BETWEEN #{start} AND #{end}
AND owner_user_id = #{userId}

SELECT user_id as userId, COUNT(DISTINCT customer_id) as count FROM (
    SELECT owner_user_id as user_id, id as customer_id FROM customers
    WHERE is_deleted = 0 AND created_at BETWEEN #{start} AND #{end}
    AND owner_user_id IN
    #{id}
    UNION ALL
    SELECT inviter_user_id as user_id, id as customer_id FROM customers
    WHERE is_deleted = 0 AND created_at BETWEEN #{start} AND #{end}
    AND inviter_user_id IN
    #{id}
) t
GROUP BY user_id

SELECT user_id as userId, COUNT(*) as count
FROM customer_follow_ups
WHERE is_deleted = 0 AND created_at BETWEEN #{start} AND #{end}
AND user_id IN
#{id}
